// Extract uploaded file (base64) and any text fields from the multipart form
const body = $input.first().json.body || {};
const binary = $input.first().binary || {};

// Support both form-data file upload and JSON with base64
let fileData = null;
let fileName = 'manual.docx';

if (binary && Object.keys(binary).length > 0) {
  // File came as binary attachment
  const key = Object.keys(binary)[0];
  fileData = binary[key].data;
  fileName = binary[key].fileName || fileName;
} else if (body.file) {
  fileData = body.file;
  fileName = body.fileName || fileName;
}

return [{
  json: {
    fileData,
    fileName,
    studentName: body.studentName || 'Huzaifa Tariq',
    studentId:   body.studentId   || '230201039',
    labNumber:   body.labNumber   || 'auto',
    instructor:  body.instructor  || 'Mam Madiha',
    subject:     body.subject     || 'ML Lab',
    department:  body.department  || 'Computer Science'
  },
  binary: binary
}];

