// Parse Claude's JSON response
const response = $input.first().json;
const content = response.content?.[0]?.text || '';

let parsed;
try {
  // Strip any accidental markdown fences
  const clean = content.replace(/```json\n?|```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  // Attempt lenient extraction
  const match = content.match(/\{[\s\S]+\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch(e2) { throw new Error('Claude did not return valid JSON: ' + content.slice(0, 200)); }
  } else {
    throw new Error('No JSON found in Claude response: ' + content.slice(0, 200));
  }
}

// Carry forward student info
const meta = $('Parse Upload').first().json;

return [{
  json: {
    labNumber:   parsed.labNumber  || meta.labNumber,
    labName:     parsed.labName    || 'Lab',
    subject:     parsed.subject    || meta.subject,
    studentName: meta.studentName,
    studentId:   meta.studentId,
    instructor:  meta.instructor,
    department:  meta.department,
    tasks:       parsed.tasks      || []
  }
}];

// Alternative: run the script via n8n's built-in shell execution
// This node provides the script for manual execution or passes it through
const data = $input.first().json;

// If Python executor returned base64 docx, extract it
const docxBase64 = data.fileBase64 || data.result || data.output || null;

return [{
  json: {
    success: true,
    labNumber:   data.labNumber,
    labName:     data.labName,
    studentName: data.studentName,
    taskCount:   (data.tasks || []).length,
    docxBase64,
    script:      data.script,
    message: docxBase64
      ? `Lab Report ${data.labNumber} generated successfully with ${(data.tasks||[]).length} task(s).`
      : `Script ready. Lab ${data.labNumber} - ${(data.tasks||[]).length} tasks extracted. Run the script manually or connect a Python executor.`
  }
}];
